<html dir="ltr">
<head>
    <base href="res://ieframe.dll">
    <link rel="stylesheet" type="text/css" href="ErrorPageTemplate.css">
    <meta http-equiv="Content-Type" content="text/html; charset=UTF-8">
    <title>–Э–µ —Г–і–∞–ї–Њ—Б—М —Б–Ї–∞—З–∞—В—М –і–∞–љ–љ—Л–µ –≤–µ–±-–Ї–∞–љ–∞–ї–∞</title>

    <script src="errorPageStrings.js" language="javascript" type="text/javascript">
    </script>

    <script src="httpErrorPagesScripts.js" language="javascript" type="text/javascript">
    </script>

</head>
<body onload="initGoBack();">
    <table width="730" cellpadding="0" cellspacing="0" border="0">
        <!-- Error title -->
        <tr>
            <td id="infoIconAlign" width="60" valign="top" rowspan="2">
                <img src="info_48.png" id="infoIcon" alt="–Ч–љ–∞—З–Њ–Ї –Є–љ—Д–Њ—А–Љ–∞—Ж–Є–Є">
            </td>
            <td id="mainTitleAlign" valign="middle" width="*">
                <h1 id="mainTitle">
                    –С—А–∞—Г–Ј–µ—А—Г Internet Explorer –љ–µ —Г–і–∞–µ—В—Б—П –Њ—В–Њ–±—А–∞–Ј–Є—В—М —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї</h1>
            </td>
        </tr>
        <tr>
            <!-- This row is for HTTP status code, as well as the divider-->
            <td id="errorCodeAlign" class="errorCodeAndDivider" align="right">
                <div class="divider">
                </div>
            </td>
        </tr>
        <!-- Error Body -->
        <tr>
            <td>
                &nbsp;
            </td>
            <td id="likelyCausesAlign" valign="top" >
                <h3 id="likelyCauses">
                    –Т Internet Explorer –љ–µ—В –њ—А–∞–≤–Є–ї—М–љ–Њ–≥–Њ –Є–Љ–µ–љ–Є –њ–Њ–ї—М–Ј–Њ–≤–∞—В–µ–ї—П –Є –њ–∞—А–Њ–ї—П –і–ї—П –і–Њ—Б—В—Г–њ–∞ –Ї —Н—В–Њ–Љ—Г –≤–µ–±-–Ї–∞–љ–∞–ї—Г.</h3>
            </td>
        </tr>
      
        <!-- back to previous page -->
        <tr>
            <td>
                &nbsp;
            </td>
            <td id="goBackAlign" valign="middle">
                <h4>
                    <table>
                        <tr>
                            <td valign="top">
                                <img src="bullet.png" border="0" alt="" class="actionIcon"><span id="goBackContainer"></span>
                            </td>
                            <td valign="top">
                                <noscript id="goBack">–Т–µ—А–љ–Є—В–µ—Б—М –љ–∞ –њ—А–µ–і—Л–і—Г—Й—Г—О —Б—В—А–∞–љ–Є—Ж—Г.</noscript>
                            </td>
                        </tr>
                    </table>
                </h4>
            </td>
        </tr>

    </table>
</body>
</html><?xml version="1.0" encoding="utf-8"?>
<xsl:stylesheet xmlns:xsl="http://www.w3.org/1999/XSL/Transform" xmlns:wfw="http://wellformedweb.org/CommentAPI/" xmlns:slash="http://purl.org/rss/1.0/modules/slash/" xmlns:content="http://purl.org/rss/1.0/modules/content/" xmlns:feedui="url:schemas-microsoft-com:feed-ui" xmlns:msxsl="urn:schemas-microsoft-com:xslt" xmlns:cfi="http://www.microsoft.com/schemas/rss/core/2005/internal" version="1.0">

  <!-- Output method is XML even though we output the HTML fragment here. Don't add dependencies on the specifics of the HTML output method,
  and the result has to be a valid XML. See bug 1715807 for more info. -->
  <xsl:output method="xml" omit-xml-declaration="yes"/>
    
  <xsl:template match="/rss/channel">

    <!-- Feed name could be optional, so we use Untitled in that case -->
    <xsl:variable name="feedTitle">
      <xsl:choose>
          <xsl:when test="title"><xsl:value-of select="title"/></xsl:when>
          <xsl:otherwise>–С–µ–Ј –Є–Љ–µ–љ–Є</xsl:otherwise>
      </xsl:choose>
    </xsl:variable>

    <!-- Sync engine turned off warning box -->
    <div id="_syncwarnheader_" class="__feedview__syncengineheader" style="display: none;">
        <div><b><span class="__feedview__loctxt">–Т–µ–±-–Ї–∞–љ–∞–ї—Л, –љ–∞ –Ї–Њ—В–Њ—А—Л–µ –≤—Л –њ–Њ–і–њ–Є—Б–∞–љ—Л, –љ–µ –Њ–±–љ–Њ–≤–ї—П—О—В—Б—П –∞–≤—В–Њ–Љ–∞—В–Є—З–µ—Б–Ї–Є, —В–∞–Ї –Ї–∞–Ї —Н—В–Њ—В –њ–∞—А–∞–Љ–µ—В—А –Њ—В–Ї–ї—О—З–µ–љ.</span></b></div>
        <div><img src="res://ieframe.dll/syncengine.png" border="0"/><span class="__feedview__loctxt"><a href="#" id="_turnonsynceng_">–Т–Ї–ї—О—З–Є—В—М –∞–≤—В–Њ–Љ–∞—В–Є—З–µ—Б–Ї–Њ–µ –Њ–±–љ–Њ–≤–ї–µ–љ–Є–µ –≤–µ–±-–Ї–∞–љ–∞–ї–Њ–≤</a></span></div>
    </div>

   <!-- Just Subscribed Help Box -->
   <div id="_justsubscribedhelpheader_" class="__feedview__justsubscribedhelpheader" style="display: none;">
      
          <div id="_miniexphelpnondocked_" style="display: none;">
              <p><b><span class="__feedview__loctxt">–Т—Л —Г—Б–њ–µ—И–љ–Њ –њ–Њ–і–њ–Є—Б–∞–ї–Є—Б—М –љ–∞ —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї</span></b></p>
              <p><span class="__feedview__loctxt">–Ю–±–љ–Њ–≤–ї–µ–љ–љ–Њ–µ —Б–Њ–і–µ—А–ґ–Є–Љ–Њ–µ –Љ–Њ–ґ–љ–Њ –њ—А–Њ—Б–Љ–∞—В—А–Є–≤–∞—В—М —Б –њ–Њ–Љ–Њ—Й—М—О Internet Explorer –Є–ї–Є –і—А—Г–≥–Є—Е –њ—А–Њ–≥—А–∞–Љ–Љ, –њ–Њ–і–і–µ—А–ґ–Є–≤–∞—О—Й–Є—Е –Њ–±—Й–Є–є —Б–њ–Є—Б–Њ–Ї –≤–µ–±-–Ї–∞–љ–∞–ї–Њ–≤.</span></p>
              <p class="__feedview__justsubscribedbutton"><a href="#" id="_viewminiexpfeeds_"><img id="_viewminiexpfeeds_" src="res://ieframe.dll/favcenter.png" border="0"/><span id="_viewminiexpfeeds_" class="__feedview__loctxt">–Я—А–Њ—Б–Љ–Њ—В—А –≤–µ–±-–Ї–∞–љ–∞–ї–Њ–≤</span></a></p>
          </div>
       
          <div id="_miniexphelpdocked_" style="display: none;">
              <p><b><span class="__feedview__loctxt">–Т—Л —Г—Б–њ–µ—И–љ–Њ –њ–Њ–і–њ–Є—Б–∞–ї–Є—Б—М –љ–∞ —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї</span></b></p>
          </div>

   </div>

    <!-- Subscribe header when feed is in preview mode -->
    <div id="_subscribeheader_" class="__feedview__subscribeheader" style="display: none;">
       
        <xsl:choose>
            <xsl:when test="link"><div class="__feedview__subscribeheadertitle"><a href="{link}" title="{link}"><xsl:value-of select="$feedTitle"/></a></div></xsl:when>
            <xsl:otherwise><div class="__feedview__subscribeheadertitle"><xsl:value-of select="$feedTitle"/></div></xsl:otherwise>
        </xsl:choose>

        <p><span class="__feedview__loctxt"><b>–Т—Л –њ—А–Њ—Б–Љ–∞—В—А–Є–≤–∞–µ—В–µ –≤–µ–±-–Ї–∞–љ–∞–ї, –Ї–Њ—В–Њ—А—Л–є —З–∞—Б—В–Њ –Њ–±–љ–Њ–≤–ї—П–µ—В—Б—П.</b> –Ъ–Њ–≥–і–∞ –≤—Л –њ–Њ–і–њ–Є—Б—Л–≤–∞–µ—В–µ—Б—М –љ–∞ –≤–µ–±-–Ї–∞–љ–∞–ї, –Њ–љ –і–Њ–±–∞–≤–ї—П–µ—В—Б—П –≤ –Њ–±—Й–Є–є —Б–њ–Є—Б–Њ–Ї –≤–µ–±-–Ї–∞–љ–∞–ї–Њ–≤. –Ю–±–љ–Њ–≤–ї–µ–љ–љ–∞—П –Є–љ—Д–Њ—А–Љ–∞—Ж–Є—П –Є–Ј –≤–µ–±-–Ї–∞–љ–∞–ї–∞ –∞–≤—В–Њ–Љ–∞—В–Є—З–µ—Б–Ї–Є —Б–Ї–∞—З–Є–≤–∞–µ—В—Б—П –љ–∞ –≤–∞—И –Ї–Њ–Љ–њ—М—О—В–µ—А, –Є –µ–µ –Љ–Њ–ґ–љ–Њ –њ—А–Њ—Б–Љ–∞—В—А–Є–≤–∞—В—М —Б –њ–Њ–Љ–Њ—Й—М—О Internet Explorer –Є–ї–Є –і—А—Г–≥–Є—Е –њ—А–Њ–≥—А–∞–Љ–Љ. <a href="#" id="_aboutfeedshelp_">–Я–Њ–і—А–Њ–±–љ–µ–µ –Њ –≤–µ–±-–Ї–∞–љ–∞–ї–∞—Е.</a></span></p>
        <p class="__feedview__subscribeheaderbutton"><a id="_subscribe_" href="#"><img border="0" src="res://ieframe.dll/Subscribe_feed.gif" id="_subscribe_" alt="–Ъ–љ–Њ–њ–Ї–∞ ''–Я–ї—О—Б''"/><span id="_subscribe_" class="__feedview__loctxt">–Я–Њ–і–њ–Є—Б–∞—В—М—Б—П –љ–∞ —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї</span></a></p>
    
    </div>

    <!-- Inline error messages -->
    <xsl:choose>
      <xsl:when test="@cfi:lastdownloaderror!='None'">
          <div class="__feedview__inlineerror">
              <span class="__feedview__loctxt">
                <xsl:choose>
                    <xsl:when test="@cfi:lastdownloaderror='Failed'">Internet Explorer –љ–µ —Г–і–∞–ї–Њ—Б—М –Њ–±–љ–Њ–≤–Є—В—М —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї. –Я–Њ–њ—Л—В–Ї–∞ –±—Г–і–µ—В –њ–Њ–≤—В–Њ—А–µ–љ–∞ –њ–Њ–Ј–ґ–µ.</xsl:when>
                    <xsl:when test="@cfi:lastdownloaderror='Invalid Feed Format'">–≠—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї –Є–Ј–Љ–µ–љ–Є–ї —Д–Њ—А–Љ–∞—В –і–∞–љ–љ—Л—Е, –Є Internet Explorer –љ–µ —Г–і–∞–ї–Њ—Б—М –Њ–±–љ–Њ–≤–Є—В—М –µ–≥–Њ.</xsl:when>
                    <xsl:when test="@cfi:lastdownloaderror='Normalization Failed'">–≠—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї —Б–Њ–і–µ—А–ґ–Є—В –Њ—И–Є–±–Ї–Є. <span class="__feedview__inlineerror_fontweightnormal">Internet Explorer –њ–Њ–њ—Л—В–∞–µ—В—Б—П –Њ–±–љ–Њ–≤–Є—В—М —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї –њ–Њ–Ј–і–љ–µ–µ.</span></xsl:when>
                    <xsl:when test="@cfi:lastdownloaderror='Auth Failed'">Internet Explorer –љ–µ —Г–і–∞–ї–Њ—Б—М –Њ–±–љ–Њ–≤–Є—В—М —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї, –Ј–∞—Й–Є—Й–µ–љ–љ—Л–є –њ–∞—А–Њ–ї–µ–Љ.</xsl:when>
                    <xsl:when test="@cfi:lastdownloaderror='Access Denied'">Internet Explorer –љ–µ —Г–і–∞–ї–Њ—Б—М –Њ–±–љ–Њ–≤–Є—В—М —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї, –Ј–∞—Й–Є—Й–µ–љ–љ—Л–є –њ–∞—А–Њ–ї–µ–Љ.</xsl:when>
                    <xsl:when test="@cfi:lastdownloaderror='Auth Denied'">Internet Explorer –љ–µ —Г–і–∞–ї–Њ—Б—М –Њ–±–љ–Њ–≤–Є—В—М —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї, –Ј–∞—Й–Є—Й–µ–љ–љ—Л–є –њ–∞—А–Њ–ї–µ–Љ. <span class="__feedview__inlineerror_fontweightnormal">–Я—А–Њ–≤–µ—А–Ї–∞ –њ–Њ–і–ї–Є–љ–љ–Њ—Б—В–Є –Ј–∞–њ—А–µ—Й–µ–љ–∞.</span></xsl:when>
                    <xsl:when test="@cfi:lastdownloaderror='Not Exist'">–≠—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї –±–Њ–ї—М—И–µ –љ–µ —Б—Г—Й–µ—Б—В–≤—Г–µ—В.</xsl:when>
                    <xsl:when test="@cfi:lastdownloaderror='Unsupported DTD'">–Т–µ–±-–Ї–∞–љ–∞–ї—Л —Б DTD –љ–µ –њ–Њ–і–і–µ—А–ґ–Є–≤–∞—О—В—Б—П.</xsl:when>
                    <xsl:when test="@cfi:lastdownloaderror='Size Limit Exceeded'">Internet Explorer –љ–µ —Г–і–∞–ї–Њ—Б—М –Њ–±–љ–Њ–≤–Є—В—М —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї, —В–∞–Ї –Ї–∞–Ї —А–∞–Ј–Љ–µ—А —Б–Њ–і–µ—А–ґ–Є–Љ–Њ–≥–Њ –њ—А–µ–≤—Л—И–∞–µ—В –Њ–≥—А–∞–љ–Є—З–µ–љ–Є–µ —А–∞–Ј–Љ–µ—А–∞ –і–ї—П —Б–Ї–∞—З–Є–≤–∞–љ–Є—П.</xsl:when>
                    <xsl:otherwise>Internet Explorer –љ–µ —Г–і–∞–ї–Њ—Б—М –Њ–±–љ–Њ–≤–Є—В—М —Н—В–Њ—В –≤–µ–±-–Ї–∞–љ–∞–ї.</xsl:otherwise>
                </xsl:choose>
              </span>
              <xsl:choose>
                <xsl:when test="@cfi:lastdownloaderror='Auth Failed' or @cfi:lastdownloaderror='Access Denied'">
                  <p class="__feedview__subscribeheaderbutton">
                    <a href="#" id="_viewfeedauthandrefresh_">
                      <img id="_viewfeedauthandrefresh_" border="0" src="res://ieframe.dll/keysauth.png" alt="–Ч–љ–∞—З–Њ–Ї –њ–∞—А–Њ–ї—П"/>
                      <span id="_viewfeedauthandrefresh_" class="__feedview__loctxt __feedview__inlineerror_fontweightnormal">–Ю–±–љ–Њ–≤–ї–µ–љ–Є–µ –Є–Љ–µ–љ–Є –њ–Њ–ї—М–Ј–Њ–≤–∞—В–µ–ї—П –Є –њ–∞—А–Њ–ї—П</span>
                    </a>
                  </p>
                </xsl:when>
              </xsl:choose>
          </div>
      </xsl:when>
    </xsl:choose>

